import React from 'react'
import Logo from "../assets/Logo"
import { Link } from 'react-router-dom'

function Navbar() {
  return (
    <div>
        <Link to="/">
            <img src = {Logo} />
        </Link>
    </div>
  )
}

export default Navbar
